#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } Vec3;
typedef struct { int hit; Vec3 point; Vec3 normal; float t; } Hit;

static Vec3 normalize(Vec3 a){
    float len = sqrtf(a.x*a.x + a.y*a.y + a.z*a.z);
    Vec3 r = { a.x/len, a.y/len, a.z/len };
    return r;
}

static Hit sphere_intersect(Vec3 O, Vec3 D, Vec3 C, float R){
    Hit h; h.hit = 0; h.point.x=h.point.y=h.point.z=0.0f;
    h.normal.x=h.normal.y=h.normal.z=0.0f; h.t=0.0f;
    Vec3 oc = { O.x-C.x, O.y-C.y, O.z-C.z };
    float a = D.x*D.x + D.y*D.y + D.z*D.z;
    float b = 2.0f*(oc.x*D.x + oc.y*D.y + oc.z*D.z);
    float c = (oc.x*oc.x + oc.y*oc.y + oc.z*oc.z) - R*R;
    float disc = b*b - 4.0f*a*c;
    if (disc < 0.0f) return h;
    double sd = sqrt(disc);
    float t = (-b - sd) / (2.0f*a);
    if (t < 0.001f){
        t = (-b + sd) / (2.0f*a);
        if (t < 0.001f) return h;
    }
    Vec3 P = { O.x + D.x*t, O.y + D.y*t, O.z + D.z*t };
    Vec3 n = { P.x-C.x, P.y-C.y, P.z-C.z };
    float nl = sqrtf(n.x*n.x + n.y*n.y + n.z*n.z);
    n.x/=nl; n.y/=nl; n.z/=nl;
    h.hit = 1; h.point = P; h.normal = n; h.t = t;
    return h;
}

static Vec3 sky_color(float dy){
    float t = (dy + 1.0f)*0.5f;
    Vec3 c;
    c.x = t*0.5f + (1.0f - t);
    c.y = t*0.7f + (1.0f - t);
    c.z = t*1.0f + (1.0f - t);
    return c;
}

static Vec3 **allocate_image(int w, int h){
    Vec3 **img = malloc(h*sizeof(Vec3*));
    for (int y=0; y<h; y++) img[y] = malloc(w*3*sizeof(float));
    return img;
}

static void free_image(Vec3 **img, int h){
    for (int y=0; y<h; y++) free(img[y]);
    free(img);
}

static void write_image(const char *fn, Vec3 **img, int w, int h){
    FILE *fp = fopen(fn, "w");
    if (!fp){ fprintf(stderr, "Error: Could not open file for writing\n"); return; }
    fprintf(fp, "P3\n%d %d\n255\n", w, h);
    for (int y=0; y<h; y++){
        for (int x=0; x<w; x++){
            float r = img[y][x].x, g = img[y][x].y, b = img[y][x].z;
            int ir = (int)((float)fmin(fmax((double)r,0.0),1.0) * 255.99f);
            int ig = (int)((float)fmin(fmax((double)g,0.0),1.0) * 255.99f);
            int ib = (int)((float)fmin(fmax((double)b,0.0),1.0) * 255.99f);
            fprintf(fp, "%d %d %d\n", ir, ig, ib);
        }
    }
    fclose(fp);
    fprintf(stderr, "Wrote image to %s\n", fn);
}

int main(void){
    int W = 800, H = 600;
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", W, H);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");

    Vec3 origin = { 0.0f, 0.0f, 0.0f };
    Vec3 C = { 0.0f, -0.5f, -5.0f };
    float R = 1.0f;
    Vec3 light = normalize((Vec3){ 1.0f, 1.0f, -1.0f });

    Vec3 **img = allocate_image(W, H);
    fprintf(stderr, "Rendering high-resolution image...\n");

    for (int y=0; y<H; y++){
        fprintf(stderr, "\rProgress: %.1f%%", 100.0f * y / 600.0f);
        for (int x=0; x<W; x++){
            float u = x / 799.0f;
            float v = y / 599.0f;
            Vec3 dir = { u*(8.0f/3.0f) - (4.0f/3.0f), 2.0f*(1.0f - v) - 1.0f, -1.0f };
            dir = normalize(dir);

            Hit hs = sphere_intersect(origin, dir, C, R);

            int plane_hit = 0;
            float tp = 0.0f;
            if (fabsf(dir.y) >= 0.0001f){
                tp = -1.5f / dir.y;
                if (tp >= 0.001f) plane_hit = 1;
            }

            int use_sphere = 0, use_plane = 0, use_sky = 0;
            if (plane_hit){
                if (hs.hit){
                    if (tp > hs.t) use_sphere = 1; else use_plane = 1;
                } else use_plane = 1;
            } else {
                if (hs.hit) use_sphere = 1; else use_sky = 1;
            }

            Vec3 color;
            if (use_sky){
                color = sky_color(dir.y);
            } else {
                Vec3 P, N;
                if (use_plane){
                    P.x = origin.x + dir.x*tp;
                    P.y = origin.y + dir.y*tp;
                    P.z = origin.z + dir.z*tp;
                    N.x = 0.0f; N.y = 1.0f; N.z = 0.0f;
                } else {
                    P = hs.point; N = hs.normal;
                }
                Vec3 sl = normalize(light);
                Hit sh = sphere_intersect(P, sl, C, R);
                float d;
                if (sh.hit){
                    d = 0.2f;
                } else {
                    float dt = N.x*light.x + N.y*light.y + N.z*light.z;
                    d = 0.2f + 0.8f * (float)fmax((double)dt, 0.0);
                }
                if (use_plane){
                    int cell = (int)(floorf(P.x) + floorf(P.z));
                    float checker = (cell & 1) ? 0.4f : 0.9f;
                    color.x = checker*d; color.y = checker*d; color.z = checker*d;
                } else {
                    color.x = d; color.y = 0.2f*d; color.z = 0.2f*d;
                }
            }
            img[y][x] = color;
        }
    }

    fprintf(stderr, "\nRendering complete\n");
    write_image("image.ppm", img, W, H);
    free_image(img, H);
    fprintf(stderr, "Done.\n");
    return 0;
}

