#include <stdio.h>
#include <math.h>
typedef struct { float x, y, z; } Vec3;
static Vec3 nz(Vec3 a){ float len=sqrtf(a.x*a.x+a.y*a.y+a.z*a.z); Vec3 r={a.x/len,a.y/len,a.z/len}; return r; }
static float discf(Vec3 P, Vec3 D, Vec3 C, float R){
  Vec3 oc={P.x-C.x,P.y-C.y,P.z-C.z};
  float a=D.x*D.x+D.y*D.y+D.z*D.z;
  float b=2.0f*(oc.x*D.x+oc.y*D.y+oc.z*D.z);
  float c=(oc.x*oc.x+oc.y*oc.y+oc.z*oc.z)-R*R;
  return b*b-4.0f*a*c;
}
int main(){
  Vec3 C={0.0f,-0.5f,-5.0f}; float R=1.0f;
  Vec3 light=nz((Vec3){1,1,-1});
  int y=458;
  for(int x=156;x<=162;x++){
    float u=x/799.0f,v=y/599.0f;
    Vec3 dir={u*(8.0f/3.0f)-(4.0f/3.0f),2.0f*(1.0f-v)-1.0f,-1.0f};
    dir=nz(dir);
    float tp=-1.5f/dir.y;
    Vec3 P={0.0f+dir.x*tp,0.0f+dir.y*tp,0.0f+dir.z*tp};
    float d_dbl=discf(P, nz(light), C, R);   // double-normalized light
    float d_sgl=discf(P, light, C, R);       // single
    float d_raw=discf(P, (Vec3){1,1,-1}, C, R);
    printf("x=%d disc_dbl=%.6g disc_sgl=%.6g disc_raw=%.6g\n",x,d_dbl,d_sgl,d_raw);
  }
  return 0;
}
